```ts
interface Agent { pv: number }
function totalPV(liste: Agent[]): number {
  return liste.reduce((s: number, a: Agent) => s + a.pv, 0)
}
console.log(totalPV([{ pv: 12 }, { pv: 18 }, { pv: 12 }]))
```

